const API_KEY = 'YOUR_SECRET_API_KEY';

const webhookData = $('Webhook GET /get-data').first().json;
const incomingKey = webhookData?.headers?.['x-api-key'] || '';
if (incomingKey !== API_KEY) {
  return [{ json: { __unauthorized: true } }];
}

const drivers = $('קרא נהגים').all()
  .map(r => r.json['שם_נהג'])
  .filter(Boolean);

const stationRows = $('קרא תחנות').all();
const routes = {};
for (const row of stationRows) {
  const r = row.json;
  const routeName = r['מסלול'];
  if (!routeName) continue;
  if (!routes[routeName]) routes[routeName] = [];
  routes[routeName].push({
    name: r['שם_תחנה'] || '',
    lat:  r['lat']  ? Number(r['lat'])  : undefined,
    lon:  r['lon']  ? Number(r['lon'])  : undefined,
    סוג:  r['סוג'] || 'צומת',
    סדר:  Number(r['סדר'] || 0)
  });
}
for (const key of Object.keys(routes)) {
  routes[key].sort((a, b) => a.סדר - b.סדר);
}

return [{ json: { drivers, routes } }];

// ============================================================
// לוגיקה ראשית — זיהוי עיר לפי Nominatim + הכרזות
// ============================================================
// זיהוי עיר: Nominatim מחזיר address.city בכל פינג.
// משווים לשם העיר שהוגדר במסלול — אמין לכל נתיב יציאה!
// ============================================================

const API_KEY = 'YOUR_SECRET_API_KEY';
const CITY_INTERVAL_MIN  = 3;
const AUTO_TERMINATE_MIN = 30;
const STATION_RADIUS_M   = 150;

// --- בדיקת מפתח ---
const wb  = $('Webhook POST /track').first().json;
const key = wb?.headers?.['x-api-key'] || '';
if (key !== API_KEY) return [{ json: { __unauthorized: true } }];

const body = wb?.body || {};
const { driver, route, lat, lon, timestamp, stationIndex } = body;
if (!driver || !route || lat == null || lon == null) {
  return [{ json: { __error: 'שדות חסרים' } }];
}

// --- Haversine ---
function haversine(lat1, lon1, lat2, lon2) {
  const R = 6371000;
  const φ1 = lat1*Math.PI/180, φ2 = lat2*Math.PI/180;
  const Δφ = (lat2-lat1)*Math.PI/180, Δλ = (lon2-lon1)*Math.PI/180;
  const a = Math.sin(Δφ/2)**2 + Math.cos(φ1)*Math.cos(φ2)*Math.sin(Δλ/2)**2;
  return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
}

// --- נתוני Nominatim ---
// Nominatim מחזיר שם עיר + שם רחוב בכל פינג
// זה מאפשר זיהוי עיר אמין ללא תלות בנתיב הנסיעה
const geo         = $('Nominatim — מיקום נוכחי').first().json;
const currentRoad = geo?.address?.road || geo?.address?.suburb || geo?.address?.neighbourhood || '';
const currentCity = geo?.address?.city || geo?.address?.town   || geo?.address?.village       || '';

// --- זיהוי עיר: האם עברנו תחנת כניסה_עיר? ---
const cityEntryIdx = stations.findIndex(s => s['סוג'] === 'כניסה_עיר');
const inCity = cityEntryIdx !== -1 && curIdx >= cityEntryIdx;

// --- תחנות המסלול ---
const stations = $('קרא תחנות').all()
  .map(r => r.json)
  .filter(s => s['מסלול'] === route)
  .sort((a, b) => Number(a['סדר']) - Number(b['סדר']));

// --- מצב נהג ---
const stateRows    = $('קרא מצב נהג').all().map(r => r.json);
const driverState  = stateRows
  .filter(r => r['נהג'] === driver && r['מסלול'] === route)
  .sort((a, b) => new Date(b['timestamp']) - new Date(a['timestamp']))[0] || null;

const lastKnownIdx      = driverState ? Number(driverState['תחנה_נוכחית'] ?? -1) : -1;
const lastAnnounceISO   = driverState?.['זמן_הכרזה_אחרונה'] || null;
const reachedFinalISO   = driverState?.['זמן_תחנה_אחרונה']  || null;

// --- זמן ---
const now              = new Date(timestamp);
const timeStr          = now.toLocaleTimeString('he-IL', { hour: '2-digit', minute: '2-digit' });
const minSinceAnnounce = lastAnnounceISO ? (now - new Date(lastAnnounceISO)) / 60000 : 999;
const curIdx           = Number(stationIndex ?? -1);

// --- תחנה חדשה שהגיע אליה? ---
const newStationReached = curIdx > lastKnownIdx && curIdx >= 0;
const curStation        = newStationReached ? (stations[curIdx] || null) : null;
const stationType       = curStation?.['סוג'] || 'צומת';
const isLastStation     = curIdx >= stations.length - 1 && stations.length > 0;

// --- בנה הכרזה ---
let announcementText  = null;
let announcementType  = null;
let terminate         = false;
let newReachedFinalISO = reachedFinalISO;
let newLastAnnounceISO = lastAnnounceISO;

if (isLastStation && newStationReached && !reachedFinalISO) {
  // ===== תחנה אחרונה =====
  announcementType   = 'סיום_נסיעה';
  announcementText   = `השעה ${timeStr}, ההסעה הגיעה לתחנה הסופית ${curStation?.['שם_תחנה'] || ''}. תודה על נסיעה נעימה`;
  newReachedFinalISO = now.toISOString();
  newLastAnnounceISO = now.toISOString();

} else if (reachedFinalISO) {
  // ===== ממתין 30 דקות אחרי תחנה אחרונה =====
  const minSinceFinal = (now - new Date(reachedFinalISO)) / 60000;
  if (minSinceFinal >= AUTO_TERMINATE_MIN) terminate = true;

} else if (newStationReached && curStation) {
  // ===== צומת / כניסה לעיר =====
  if (stationType === 'כניסה_עיר') {
    announcementType   = 'כניסה_לעיר';
    announcementText   = `השעה ${timeStr}, ההסעה מתקרבת לעיר דרך ${curStation['שם_תחנה']}`;
    newLastAnnounceISO = now.toISOString();
  } else {
    announcementType   = 'צומת';
    announcementText   = `השעה ${timeStr}, ההסעה בקרבת ${curStation['שם_תחנה']}`;
    newLastAnnounceISO = now.toISOString();
  }

} else if (inCity && minSinceAnnounce >= CITY_INTERVAL_MIN) {
  // ===== מצב עיר — כל 3 דקות עם שם רחוב מ-Nominatim =====
  announcementType   = 'עיר_3_דקות';
  const streetPart   = currentRoad ? `רחוב ${currentRoad}` : 'אזור העיר';
  announcementText   = `השעה ${timeStr}, ההסעה נמצאת ב${streetPart}`;
  newLastAnnounceISO = now.toISOString();
}

const shouldLog         = announcementText !== null;
const shouldUpdateState = newStationReached || shouldLog || terminate;

return [{
  json: {
    driver, route, lat, lon, timestamp,
    stationIndex: curIdx,
    stationName:  curStation?.['שם_תחנה'] || null,
    announcementType,
    announcementText,
    terminate,
    inCity,
    currentCity,
    currentRoad,
    newReachedFinalISO,
    newLastAnnounceISO,
    timeStr,
    shouldLog,
    shouldUpdateState,
    __unauthorized: false
  }
}];
